import React, { useState } from 'react';
import Sidebar from '../components/Sidebar';
import Navbar from '../components/Navbar';

const BrowseCars = () => {
  const [filter, setFilter] = useState('all');
  const [price, setPrice] = useState('');
  const [seats, setSeats] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const cars = [
    {
      id: 1,
      name: 'Toyota Camry',
      type: 'sedan',
      price: 3500,
      seats: 5,
      image: 'https://www.autoindustriya.com/cdn-cgi/image/width=540,quality=50/images/new-cars/Toyota/2022_Camry-1.jpg'
    },
    {
      id: 2,
      name: 'Toyota Fortuner',
      type: 'suv',
      price: 3500,
      seats: 7,
      image: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQYMfS_G7oe5Twc70Zw5ShFjAAVRjK6tmTdLw&s'
    },
    {
      id: 3,
      name: 'Toyota Wigo',
      type: 'sedan',
      price: 1500,
      seats: 5,
      image: 'https://imgcdnblog.carmudi.com.ph/wp-content/uploads/2021/07/14150638/Toyota-Wigo-2.jpg'
    },
    {
      id: 4,
      name: 'Toyota Vios',
      type: 'sedan',
      price: 1900,
      seats: 5,
      image: 'https://i.pinimg.com/736x/55/41/b3/5541b37eb9bd4d6280dab75236aa6cc2.jpg',
      favorite: true
    },
    {
      id: 5,
      name: 'Toyota HiAce Van',
      type: 'van',
      price: 4000,
      seats: 12,
      image: 'https://toyotasantarosa.com.ph/wp-content/uploads/2021/10/Hiace_adobespark.png'
    },
    {
      id: 6,
      name: 'Toyota Hilux',
      type: 'suv',
      price: 2500,
      seats: 5,
      image: 'https://img.lazcdn.com/g/p/c4d179ffaa3d38410d45b92fcc68587b.jpg_960x960q80.jpg_.webp'
    }
  ];

  const handleFilterClick = (filterType) => {
    setFilter(filterType);
  };

  const handleSearch = (e) => {
    e.preventDefault();
    // Search logic handled by React state
  };

  const filteredCars = cars.filter(car => {
    const typeMatch = filter === 'all' || car.type === filter;
    const priceMatch = !price || car.price <= parseFloat(price);
    const seatsMatch = !seats || car.seats >= parseInt(seats);
    return typeMatch && priceMatch && seatsMatch;
  });

  return (
    <div style={styles.container}>
      <Navbar />
      <Sidebar />
      
      <div style={styles.dashboardContent}>
        <h2 style={styles.heading}>Browse Cars</h2>

        <form style={styles.filterForm} onSubmit={handleSearch}>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'all' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('all')}
          >
            All
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'sedan' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('sedan')}
          >
            Sedan
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'suv' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('suv')}
          >
            SUV
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'luxury' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('luxury')}
          >
            Luxury
          </button>
          <button 
            type="button" 
            style={{...styles.filterBtn, ...(filter === 'van' ? styles.filterBtnActive : {})}}
            onClick={() => handleFilterClick('van')}
          >
            VAN
          </button>
          <input 
            type="text" 
            placeholder="Price" 
            value={price}
            onChange={(e) => setPrice(e.target.value)}
            style={styles.input}
          />
          <input 
            type="text" 
            placeholder="Seats" 
            value={seats}
            onChange={(e) => setSeats(e.target.value)}
            style={styles.input}
          />
          <input 
            type="date" 
            value={startDate}
            onChange={(e) => setStartDate(e.target.value)}
            style={styles.input}
          />
          <input 
            type="date" 
            value={endDate}
            onChange={(e) => setEndDate(e.target.value)}
            style={styles.input}
          />
          <input type="submit" value="Search" style={styles.submitBtn} />
        </form>

        <div style={styles.carsContainer}>
          {filteredCars.length === 0 ? (
            <div style={styles.noCarsMessage}>
              There is no available cars
            </div>
          ) : (
            filteredCars.map(car => (
              <div key={car.id} style={styles.carCard}>
                {car.favorite && <span style={styles.heartIcon}>♥</span>}
                <img src={car.image} alt={car.name} style={styles.carImage} />
                <h3 style={styles.carName}>{car.name}</h3>
                <div style={styles.price}>
                  <sup>₱</sup>{car.price.toLocaleString()}.00/day
                </div>
                <div style={styles.btns}>
                  <button style={styles.bookBtn}>Book Now</button>
                  <button style={styles.viewBtn}>View Details</button>
                </div>
              </div>
            ))
          )}
        </div>

        <div style={styles.infoRow}>
          <div style={styles.infoBox}>
            <svg style={styles.infoIcon} fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path d="M3 17V9a4 4 0 0 1 4-4h10a4 4 0 0 1 4 4v8"></path>
              <rect x="3" y="13" width="18" height="8" rx="2"></rect>
            </svg>
            <div>
              <strong>Affordable Rates</strong>
              <span>Great prices on all vehicle types</span>
            </div>
          </div>
          <div style={styles.infoBox}>
            <svg style={styles.infoIcon} fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path d="M12 15v2m0-8v2m5-2a9 9 0 0 1-10 0"></path>
              <circle cx="12" cy="12" r="10"></circle>
            </svg>
            <div>
              <strong>Safety & Security</strong>
              <span>Well-maintained and safe rental cars</span>
            </div>
          </div>
          <div style={styles.infoBox}>
            <svg style={styles.infoIcon} fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24">
              <path d="M15 10l4.553-2.276a2 2 0 0 1 2.414 2.819L20 16"></path>
              <path d="M4 15v-2"></path>
              <path d="M19 10v4"></path>
              <path d="M8 12h.01"></path>
              <path d="M3 18h6"></path>
              <path d="M10 21h4"></path>
            </svg>
            <div>
              <strong>Easy Booking</strong>
              <span>Quick and hassle free online reservations</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const styles = {
  container: {
    minHeight: '100vh',
    background: '#f9fcfd',
  },
  dashboardContent: {
    marginLeft: '250px',
    marginTop: '60px',
    padding: '30px',
    overflowY: 'auto',
  },
  heading: {
    fontWeight: 'bold',
    fontSize: '24px',
    marginBottom: '15px',
    color: '#333',
  },
  filterForm: {
    background: '#fff',
    padding: '10px 15px',
    borderRadius: '8px',
    display: 'flex',
    flexWrap: 'wrap',
    alignItems: 'center',
    gap: '10px',
    marginBottom: '20px',
    border: '1px solid #d0d5dd',
  },
  filterBtn: {
    padding: '5px 12px',
    fontSize: '14px',
    borderRadius: '5px',
    border: '1px solid #444',
    background: '#fff',
    cursor: 'pointer',
    transition: 'background-color 0.3s ease',
  },
  filterBtnActive: {
    backgroundColor: '#585CE5',
    color: '#fff',
    borderColor: '#585CE5',
  },
  input: {
    padding: '6px 8px',
    fontSize: '14px',
    border: '1px solid #d0d5dd',
    borderRadius: '5px',
    width: '120px',
  },
  submitBtn: {
    padding: '5px 12px',
    fontSize: '14px',
    borderRadius: '5px',
    border: '1px solid #444',
    background: '#fff',
    cursor: 'pointer',
  },
  carsContainer: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '15px',
  },
  carCard: {
    width: '300px',
    background: '#fff',
    border: '1px solid #d8d8d8',
    borderRadius: '8px',
    boxShadow: '1px 1px 6px #ccc',
    padding: '10px',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    position: 'relative',
  },
  heartIcon: {
    position: 'absolute',
    top: '10px',
    right: '15px',
    color: '#e33539',
    fontSize: '20px',
  },
  carImage: {
    maxWidth: '260px',
    borderRadius: '8px',
  },
  carName: {
    fontWeight: 'bold',
    letterSpacing: '0.9px',
    marginTop: '8px',
    alignSelf: 'flex-start',
    color: '#333',
  },
  price: {
    fontWeight: '600',
    marginTop: '5px',
    alignSelf: 'flex-start',
    color: '#333',
  },
  btns: {
    marginTop: '12px',
    alignSelf: 'flex-start',
    display: 'flex',
    gap: '8px',
  },
  bookBtn: {
    backgroundColor: '#2d48ff',
    color: 'white',
    border: 'none',
    padding: '6px 15px',
    borderRadius: '5px',
    fontWeight: '600',
    cursor: 'pointer',
  },
  viewBtn: {
    background: 'none',
    border: 'none',
    color: '#4a6984',
    fontSize: '13px',
    cursor: 'pointer',
    padding: '0 6px',
  },
  infoRow: {
    marginTop: '40px',
    display: 'flex',
    justifyContent: 'space-between',
    background: '#f7f8fb',
    borderRadius: '8px',
    boxShadow: '0 2px 5px #ccc',
    padding: '18px 28px',
    maxWidth: '100%',
  },
  infoBox: {
    display: 'flex',
    alignItems: 'center',
    gap: '14px',
    maxWidth: '33%',
  },
  infoIcon: {
    width: '48px',
    height: '48px',
    stroke: '#222',
  },
  noCarsMessage: {
    width: '100%',
    textAlign: 'center',
    padding: '40px 20px',
    fontSize: '18px',
    color: '#666',
    fontWeight: '500',
  },
};

export default BrowseCars;
